  ('aboriginal-f7485f85-moex-00337', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-110-4dccc0e6', 'sub-aboriginal-f7485f85-02', NULL, 'single_choice', '公共政策有多種類型，請問「政府機關將某一標的人口的活動，僅做原則性規範，而由該標的人 口自行決定活動進行方式的政策」，是屬於何種政策類型？', '["重分配性政策", "管制性政策", "自我管制性政策", "分配性政策"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:11+00:00", "source_pdf_sha1": "522a4ee8e312", "answer_pdf_sha1": "2e75fe4c2425", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
